// Generated by OrchestKit Claude Plugin
// Created: 2026-06-12

/**
 * Session Identity (state) — per-session lifecycle for the haiku auto-rename
 * + auto-color flow. Called from prompt/unified-dispatcher every turn.
 *
 * Flow:
 *   turn 1: append deterministic hash-based agent-color record (instant
 *           visual distinction), spawn the detached haiku generator
 *   turn N: when the generator's JSON lands, adopt its title (prompt bar)
 *           and upgrade the color record if haiku chose a different one
 *
 * Everything fails open: a dead `claude` binary, auth failure, malformed
 * JSON, or unwritable transcript only means the session keeps its branch
 * title and hash color.
 */

import {
  appendFileSync,
  existsSync,
  mkdirSync,
  readFileSync,
  statSync,
  writeFileSync,
} from 'node:fs';
import { join } from 'node:path';
import { homedir } from 'node:os';
import type { HookContext, HookInput } from '../types.js';
import {
  CHILD_ENV_MARKER,
  hashColor,
  parseIdentityOutput,
  spawnIdentityGenerator,
  type SessionColor,
} from './session-identity.js';

/** Env kill-switch. Set ORK_SESSION_IDENTITY=0 to disable entirely. */
const ENV_KILL_SWITCH = 'ORK_SESSION_IDENTITY';

/** Give the generator this long before declaring its output unusable. */
const GENERATOR_STALE_MS = 120_000;

const FILE_RAW = 'session-identity.raw';
const FILE_PARSED = 'session-identity.json';
const FILE_SPAWNED = 'session-identity.spawned';
const FILE_COLOR_APPLIED = 'session-identity.color';
const FILE_TOMBSTONE = 'session-identity.failed';

/**
 * Resolve the session transcript path. Prefer the envelope's transcript_path;
 * fall back to the documented layout ~/.claude/projects/<cwd-slug>/<id>.jsonl
 * (slug = cwd with every non-alphanumeric char mapped to '-').
 */
export function resolveTranscriptPath(
  input: HookInput,
  projectDir: string | undefined,
): string | null {
  if (input.transcript_path && existsSync(input.transcript_path)) {
    return input.transcript_path;
  }
  if (!projectDir || !input.session_id) return null;
  const slug = projectDir.replace(/[^a-zA-Z0-9]/g, '-');
  const candidate = join(homedir(), '.claude', 'projects', slug, `${input.session_id}.jsonl`);
  return existsSync(candidate) ? candidate : null;
}

/**
 * Append the exact record `/color` writes (verified against the CC 2.1.175
 * binary: `{type:"agent-color",agentColor,sessionId}`; the session-list
 * reader takes the last record per sessionId). Single-line O_APPEND write —
 * atomic at this size, safe to interleave with CC's own appends.
 */
export function appendAgentColorRecord(
  transcriptPath: string,
  sessionId: string,
  color: SessionColor,
): boolean {
  try {
    const record = `${JSON.stringify({ type: 'agent-color', agentColor: color, sessionId })}\n`;
    appendFileSync(transcriptPath, record, 'utf8');
    return true;
  } catch {
    return false;
  }
}

/**
 * Drive the identity lifecycle for this turn. Returns the AI title once it's
 * available (the dispatcher merges it into sessionTitle), else null.
 *
 * State files live in the per-session storage dir the dispatcher already
 * uses (same tree as once-flags / last-session-title.txt).
 */
export function manageSessionIdentity(
  input: HookInput,
  ctx: HookContext,
  sessionDir: string,
  projectDir: string | undefined,
): string | null {
  try {
    if (process.env[ENV_KILL_SWITCH] === '0') return null;
    if (process.env[CHILD_ENV_MARKER] === '1') return null;
    if (!input.session_id) return null;

    const parsedPath = join(sessionDir, FILE_PARSED);
    const rawPath = join(sessionDir, FILE_RAW);
    const spawnedPath = join(sessionDir, FILE_SPAWNED);
    const colorAppliedPath = join(sessionDir, FILE_COLOR_APPLIED);
    const tombstonePath = join(sessionDir, FILE_TOMBSTONE);

    // 1. Identity already parsed → ensure color upgrade applied, return title.
    if (existsSync(parsedPath)) {
      const identity = parseIdentityOutput(readFileSync(parsedPath, 'utf8'));
      if (!identity) return null;
      applyColorOnce(input, projectDir, identity.color, colorAppliedPath, ctx);
      return identity.title;
    }

    if (existsSync(tombstonePath)) return null;

    // 2. Generator spawned earlier → try to harvest its output.
    if (existsSync(spawnedPath)) {
      if (!existsSync(rawPath)) return null;
      const raw = readFileSync(rawPath, 'utf8');
      const identity = parseIdentityOutput(raw);
      if (identity) {
        writeFileSync(parsedPath, JSON.stringify(identity), 'utf8');
        applyColorOnce(input, projectDir, identity.color, colorAppliedPath, ctx);
        ctx.log('session-identity', `haiku identity ready: "${identity.title}" (${identity.color})`);
        return identity.title;
      }
      // Unparseable + stale → stop checking every turn.
      try {
        const age = Date.now() - statSync(rawPath).mtimeMs;
        if (age > GENERATOR_STALE_MS && raw.length > 0) {
          writeFileSync(tombstonePath, raw.slice(0, 500), 'utf8');
          ctx.log('session-identity', 'generator output unparseable — giving up for this session', 'warn');
        }
      } catch {
        /* stat raced — retry next turn */
      }
      return null;
    }

    // 3. First turn: instant hash color + kick off the generator.
    if (!existsSync(sessionDir)) mkdirSync(sessionDir, { recursive: true });
    const fallback = hashColor(input.session_id);
    applyColorOnce(input, projectDir, fallback, colorAppliedPath, ctx);
    if (input.prompt && spawnIdentityGenerator(input.prompt, ctx.branch || '', rawPath, ctx)) {
      writeFileSync(spawnedPath, new Date().toISOString(), 'utf8');
    }
    return null;
  } catch (error) {
    ctx.log('session-identity', `failed open: ${error}`, 'warn');
    return null;
  }
}

/**
 * Append the agent-color record at most once per distinct color value
 * (hash color on turn 1, possibly upgraded once by the haiku pick).
 */
function applyColorOnce(
  input: HookInput,
  projectDir: string | undefined,
  color: SessionColor,
  colorAppliedPath: string,
  ctx: HookContext,
): void {
  try {
    if (existsSync(colorAppliedPath) && readFileSync(colorAppliedPath, 'utf8').trim() === color) {
      return;
    }
    const transcript = resolveTranscriptPath(input, projectDir);
    if (!transcript) return;
    if (appendAgentColorRecord(transcript, input.session_id, color)) {
      writeFileSync(colorAppliedPath, color, 'utf8');
      ctx.log('session-identity', `session color set: ${color}`);
    }
  } catch {
    /* fail open */
  }
}
